# Configure AWS provider for account 696505809372 and region eu-north-1.
# Credentials: default chain (AWS_ACCESS_KEY_ID/AWS_SECRET_ACCESS_KEY, or ~/.aws/credentials [default]).
# If you use a named profile, add: profile = "your-profile-name" (do not use account ID as profile name).

terraform {
  required_version = ">= 1.0"

  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "= 5.100.0"
    }
  }
}

provider "aws" {
  region = "eu-north-1"
}

# S3 bucket access logging - Action: 19a9b0f0-de47-4a5b-982f-8d3c876c2064
# Remediation for: S3 general purpose buckets should have server access logging enabled
# Account: 696505809372 | Region: eu-north-1 | Bucket: security-autopilot-access-logs-696505809372-r221001
# Control: S3.9

variable "source_bucket_name" {
  type        = string
  description = "S3 source bucket where server access logging is enabled"
  default     = "security-autopilot-access-logs-696505809372-r221001"
}

variable "log_bucket_name" {
  type        = string
  description = "S3 bucket that will receive access logs"
  default     = "security-autopilot-access-logs-696505809372-r221001-access-logs"
}

variable "create_log_bucket" {
  type        = bool
  description = "When true, create the destination bucket with the shared support-bucket baseline."
  default     = true
}

variable "log_prefix" {
  type        = string
  description = "Prefix for delivered access logs"
  default     = "s3-access-logs/"
}

resource "aws_s3_bucket" "access_logs" {
  count  = var.create_log_bucket ? 1 : 0
  bucket = var.log_bucket_name
}


resource "aws_s3_bucket_public_access_block" "access_logs" {
  count      = var.create_log_bucket ? 1 : 0
  bucket                  = aws_s3_bucket.access_logs[0].id
  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
  depends_on = [aws_s3_bucket.access_logs]
}

resource "aws_s3_bucket_server_side_encryption_configuration" "access_logs" {
  count      = var.create_log_bucket ? 1 : 0
  bucket = aws_s3_bucket.access_logs[0].id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm     = "aws:kms"
      kms_master_key_id = "alias/aws/s3"
    }
    bucket_key_enabled = true
  }
  depends_on = [aws_s3_bucket.access_logs]
}

resource "aws_s3_bucket_lifecycle_configuration" "access_logs" {
  count      = var.create_log_bucket ? 1 : 0
  bucket = aws_s3_bucket.access_logs[0].id

  rule {
    id     = "abort-incomplete-multipart"
    status = "Enabled"
    filter {}
    abort_incomplete_multipart_upload {
      days_after_initiation = 7
    }
  }
  depends_on = [aws_s3_bucket.access_logs]
}

data "aws_iam_policy_document" "ssl_only_access_logs" {

  statement {
    sid     = "DenyInsecureTransport"
    effect  = "Deny"
    actions = ["s3:*"]
    resources = [
      "${arn_prefix_access_logs}",
      "${arn_prefix_access_logs}/*",
    ]
    principals {
      type        = "*"
      identifiers = ["*"]
    }
    condition {
      test     = "Bool"
      variable = "aws:SecureTransport"
      values   = ["false"]
    }
  }
}

locals {
  arn_prefix_access_logs = "arn:aws:s3:::${var.log_bucket_name}"
}

resource "aws_s3_bucket_policy" "access_logs" {
  count      = var.create_log_bucket ? 1 : 0
  bucket = aws_s3_bucket.access_logs[0].id
  policy = data.aws_iam_policy_document.ssl_only_access_logs.json
  depends_on = [aws_s3_bucket.access_logs]
}


resource "aws_s3_bucket_logging" "security_autopilot" {
  bucket        = var.source_bucket_name
  target_bucket = var.log_bucket_name
  target_prefix = var.log_prefix
  depends_on    = [aws_s3_bucket_policy.access_logs]
}
